            </button>
          </div>
        </div>
      );
    }

    if (vertical === 'billboard') {
      return (
        <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm space-y-4">
          <h4 className="text-sm font-bold text-gray-900">{t('Create Billboard', 'Creer un panneau')}</h4>
          <input
            value={siteName}
