165→      <div className="text-[10px] font-bold uppercase tracking-widest text-[#0f2b46]">{label}</div>
166→      <div className="flex items-center justify-between text-[11px]">
167→        <span className="text-gray-500">{t('EXIF Status', 'Statut EXIF')}</span>
