                      </div>
                      <div className="text-[10px] text-gray-500 text-center">
                        {photo.eventType === 'CREATE_EVENT' ? t('Create', 'Creation') : photo.eventType === 'ENRICH_EVENT' ? t('Enrich', 'Enrichissement') : photo.eventType}
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              <div className="space-y-3">
