import React from 'react';
import { Award, CheckCircle, Map, PlusCircle, Zap } from 'lucide-react';

interface Props {
  language: 'en' | 'fr';
  totalXp: number;
  baseXp: number;
  qualityBonus: number;
  streakBonus: number;
  syncMessage?: string;
  isBatchMode?: boolean;
  onPrimary: () => void;
  onSecondary: () => void;
}

const XPPopup: React.FC<Props> = ({
  language,
