    if (assignment?.assignedVerticals?.[0] && !isEnrichMode) {
      setVertical(assignment.assignedVerticals[0]);
    }
  }, [assignment?.assignedVerticals, isEnrichMode, queuedDraft]);

  useEffect(() => {
    setEnrichValues({});
    setEnrichTouched({});
    setEnrichMultiRaw({});
    setMerchantId(seedPoint?.merchantId ?? '');
    setMerchantProvider(seedPoint?.providers?.[0] ?? providerOptions[0]);
    setPriceFuelType(seedPoint?.fuelType ?? fuelTypeOptions[0]);
    setPriceValue(seedPoint?.price ? String(seedPoint.price) : '');
  }, [isEnrichMode, seedPoint?.id]);

  useEffect(() => {
    if (!isEnrichMode) return;
    clearDedupPrompt();
  }, [isEnrichMode, seedPoint?.id]);

  useEffect(() => {
    if (!navigator.geolocation) return;
    navigator.geolocation.getCurrentPosition(
      (pos) => setLocation({ latitude: pos.coords.latitude, longitude: pos.coords.longitude }),
      () => setLocation(null),
      { enableHighAccuracy: true, timeout: 10000 }
