    if (fieldConfig.kind === 'single_select') {
      const value = typeof getEnrichFieldValue(gap) === 'string' ? String(getEnrichFieldValue(gap)) : '';
      if (options.length === 0) {
        return (
          <div className="space-y-2" key={gap}>
