        ? String(getEnrichFieldValue(gap))
        : '';
    return (
      <div className="space-y-2" key={gap}>
        <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{label}</label>
        <input
          value={fallbackRaw}
