    setManualLongitude('');
    setPhotoError('');
    setLocationError('');
    setErrorMessage('');
    setSyncMessage('');
    setPendingPayload(null);
    setSelectedDedupPointId('');
    setDedupCheck(null);
    setSiteName('');
    setOpeningHours('');
    setProviders([]);
    setMerchantId('');
    setPaymentMethods([]);
    setFuelTypes([]);
    setPriceValue('');
    setAdvertiserBrand('');
    setRoadName('');
    setStoreyCount('');
    setEstimatedUnits('');
    setEnrichValues({});
    setEnrichTouched({});
    setEnrichMultiRaw({});
