    const label = getEnrichFieldLabel(gap, language);
    const options = fieldConfig.options ?? [];

    if (fieldConfig.kind === 'boolean') {
      const selected = typeof getEnrichFieldValue(gap) === 'boolean' ? (getEnrichFieldValue(gap) as boolean) : null;
