              <option key={option.value} value={option.value}>{optionLabel(option, language)}</option>
            ))}
          </select>
        </div>
      );
    }

    if (fieldConfig.kind === 'multi_select') {
      const selectedValues = normalizeStringList(getEnrichFieldValue(gap));
