    const completeness = requiredFields.length > 0 ? Math.round((filledCount / requiredFields.length) * 100) : 100;
    const estimatedXp = BASE_EVENT_XP + (gpsScore >= 60 ? 2 : 0) + (completeness >= 100 ? 1 : 0);
