  const [dedupCheck, setDedupCheck] = useState<DedupCheckResult | null>(null);
  const [pendingPayload, setPendingPayload] = useState<SubmissionInput | null>(null);
  const [selectedDedupPointId, setSelectedDedupPointId] = useState('');
