  const [xpBreakdown, setXpBreakdown] = useState({ baseXp: 5, qualityBonus: 0, streakBonus: 0, totalXp: 5 });
  const [gpsAccuracy, setGpsAccuracy] = useState<number | null>(null);
  const [showLevelUp, setShowLevelUp] = useState(false);
