  3→import { useEffect, useRef, useState } from "react";
  4→import { Mic } from "lucide-react";
  5→
  6→interface VoiceMicButtonProps {
  7→  onResult: (text: string) => void;
  8→  language: "en" | "fr";
  9→  disabled?: boolean;
 10→}
 11→
 12→export default function VoiceMicButton({
 13→  onResult,
 14→  language,
 15→  disabled = false,
 16→}: VoiceMicButtonProps) {
 17→  const [isListening, setIsListening] = useState(false);
 18→  const [supported, setSupported] = useState(false);
 19→  const recognitionRef = useRef<SpeechRecognition | null>(null);
 20→
 21→  useEffect(() => {
 22→    const SpeechRecognition =
 23→      window.SpeechRecognition || window.webkitSpeechRecognition;
 24→    if (SpeechRecognition) {
 25→      setSupported(true);
 26→    }
 27→  }, []);
 28→
 29→  const getLang = (): string => {
 30→    if (language === "en") return "en";
 31→    // French: prefer Cameroon locale, then standard French, then bare code
 32→    const candidates = ["fr-CM", "fr-FR", "fr"];
 33→    for (const candidate of candidates) {
 34→      try {
 35→        // Attempt to create a recognition instance with the candidate to verify support
 36→        const SpeechRecognition =
 37→          window.SpeechRecognition || window.webkitSpeechRecognition;
 38→        if (SpeechRecognition) return candidate;
 39→      } catch {
 40→        continue;
 41→      }
 42→    }
 43→    return "fr";
 44→  };
 45→
 46→  const toggleListening = () => {
 47→    if (isListening) {
 48→      recognitionRef.current?.stop();
 49→      setIsListening(false);
 50→      return;
 51→    }
 52→
 53→    const SpeechRecognition =
 54→      window.SpeechRecognition || window.webkitSpeechRecognition;
 55→    if (!SpeechRecognition) return;
 56→
 57→    const recognition = new SpeechRecognition();
 58→    recognition.lang = getLang();
 59→    recognition.interimResults = false;
 60→    recognition.maxAlternatives = 1;
 61→
 62→    recognition.onresult = (event: SpeechRecognitionEvent) => {
 63→      const transcript = event.results[0]?.[0]?.transcript;
 64→      if (transcript) {
 65→        onResult(transcript);
 66→      }
 67→    };
 68→
 69→    recognition.onend = () => {
 70→      setIsListening(false);
 71→    };
 72→
 73→    recognition.onerror = () => {
 74→      setIsListening(false);
 75→    };
 76→
 77→    recognitionRef.current = recognition;
 78→    recognition.start();
 79→    setIsListening(true);
 80→  };
 81→
 82→  if (!supported) return null;
 83→
 84→  return (
 85→    <button
 86→      type="button"
 87→      disabled={disabled}
 88→      onClick={toggleListening}
 89→      aria-label={isListening ? "Stop voice input" : "Start voice input"}
 90→      className={`
 91→        inline-flex items-center justify-center h-11 w-11 rounded-xl border
 92→        transition-colors duration-200
 93→        ${
